// Dados do pedido vindos do Supabase webhook
const body = $input.first().json.body || $input.first().json;
const record = body.record || body;

const orderId      = record.id || '';
const buyerName    = record.buyer_name || '';
const buyerPhone   = (record.buyer_whatsapp || '').replace(/\D/g, '');
const totalValue   = Number(record.total_value || 0);
const createdAt    = new Date(record.created_at || Date.now())
                      .toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

// Desconto aplicado (já vem calculado no total_value)
// Monta mensagem PIX
const pixKey   = '15991460543';
const pixTipo  = 'Telefone';
const shortId  = orderId.slice(0, 8).toUpperCase();

const msg = [
  `🏷️ *Figurinhas Copa 2026 — Pedido Confirmado!*`,
  ``,
  `Olá, *${buyerName}*! Seu pedido foi recebido. 🎉`,
  ``,
  `📋 *Pedido:* #${shortId}`,
  `💰 *Total: R$ ${totalValue.toFixed(2).replace('.', ',')}*`,
  ``,
  `━━━━━━━━━━━━━━━━━`,
  `💳 *Pagamento via PIX*`,
  ``,
  `🔑 *Chave PIX (${pixTipo}):*`,
  `\`${pixKey}\``,
  ``,
  `📌 *Como pagar:*`,
  `1. Abra seu banco`,
  `2. Vá em PIX → Pagar`,
  `3. Digite a chave acima`,
  `4. Confirme o valor *R$ ${totalValue.toFixed(2).replace('.', ',')}*`,
  `5. Envie o comprovante aqui`,
  `━━━━━━━━━━━━━━━━━`,
  ``,
  `Após confirmar o pagamento separamos suas figurinhas! 📦`,
  `_Qualquer dúvida é só chamar._ 😊`
].join('\n');

return [{ json: { buyerPhone, msg, orderId: shortId, buyerName, totalValue } }];

